import { describe, expect, it, vi } from "vitest";

let hasCookie = true;
vi.mock("next/headers", () => ({
  cookies: () => ({ get: () => (hasCookie ? { value: "r-pilot-1" } : undefined) }),
}));

import { GET } from "./route";

interface OrderRow {
  id: string;
  status: string;
  placedAt: string;
  expectedDelivery: string | null;
  itemCount: number;
  totalPaise: number;
  distributor: { id: string; name: string };
}

describe("GET /api/orders", () => {
  it("defaults to active when ?status is missing", async () => {
    const res = await GET(new Request("http://localhost/api/orders"));
    expect(res.status).toBe(200);
    const body = (await res.json()) as { orders: OrderRow[] };
    for (const o of body.orders) {
      expect(["placed", "acknowledged", "out_for_delivery"]).toContain(o.status);
    }
  });

  it("returns 400 on invalid status", async () => {
    const res = await GET(new Request("http://localhost/api/orders?status=foo"));
    expect(res.status).toBe(400);
  });

  it("returns 401 without a cookie", async () => {
    hasCookie = false;
    const res = await GET(new Request("http://localhost/api/orders"));
    expect(res.status).toBe(401);
    hasCookie = true;
  });

  it("closed status returns delivered/cancelled orders", async () => {
    const res = await GET(new Request("http://localhost/api/orders?status=closed"));
    const body = (await res.json()) as { orders: OrderRow[] };
    for (const o of body.orders) {
      expect(["delivered", "cancelled"]).toContain(o.status);
    }
  });

  it("each row carries the documented fields including distributor sub-object", async () => {
    const res = await GET(new Request("http://localhost/api/orders?status=active"));
    const body = (await res.json()) as { orders: OrderRow[] };
    expect(body.orders.length).toBeGreaterThan(0);
    const o = body.orders[0];
    expect(o).toHaveProperty("distributor.id");
    expect(o).toHaveProperty("distributor.name");
    expect(typeof o.placedAt).toBe("string");
  });
});

import { describe, expect, it, vi } from "vitest";

vi.mock("next/headers", () => ({
  cookies: () => ({ get: () => ({ value: "r-pilot-1" }) }),
}));

import { POST } from "./route";
import { addCartItem, clearCart } from "@/lib/db/store";

describe("POST /api/orders", () => {
  beforeEach(() => clearCart("r-pilot-1"));

  it("returns 409 when the cart is empty", async () => {
    const res = await POST();
    expect(res.status).toBe(409);
  });

  it("fans out one order per distinct distributor and returns orderIds", async () => {
    addCartItem("r-pilot-1", "m-paracetamol-500", 1); // d-mediplus
    addCartItem("r-pilot-1", "m-vitd3-60k", 1); // d-omsai
    const res = await POST();
    expect(res.status).toBe(200);
    const body = (await res.json()) as { orderIds: string[]; orderCount: number };
    expect(body.orderCount).toBe(2);
    expect(body.orderIds).toHaveLength(2);
  });
});
